#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BS 16
#define AA(_i,_j) a[offset*size+_i*size+_j+offset]
#define BB(_i,_j) a[_i*size+_j]

__kernel void lud_diagonal(__global float* a, __local float* shared_mem, const int size, const int offset)
{
    int i = get_global_id(0);
    if (i >= BS) return;

    // Process diagonal block
    for (int j = i; j < BS; j++) {
        for (int k = 0; k < i; k++) {
            AA(i,j) = AA(i,j) - AA(i,k) * AA(k,j);
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    float temp = 1.f / AA(i,i);
    for (int j = i+1; j < BS; j++) {
        for (int k = 0; k < i; k++) {
            AA(j,i) = AA(j,i) - AA(j,k) * AA(k,i);
        }
        AA(j,i) = AA(j,i) * temp;
    }
}

__kernel void lud_perimeter(__global float* a, __local float* temp, __local float* temp2, __local float* temp3, const int size, const int offset)
{
    int gid = get_global_id(0);
    int chunk_idx = gid / 2;
    int is_row = gid % 2; // 0: row update, 1: column update

    int size_inter = size - offset - BS;
    int chunks_in_inter_row = size_inter / BS;

    if (chunk_idx >= chunks_in_inter_row) return;

    int i_global = offset;
    int j_global = offset;

    if (is_row == 0) {
        // Row update
        j_global += BS * (chunk_idx + 1);

        // Load diagonal block to temp
        for (int i = 0; i < BS; i++) {
            for (int j = 0; j < BS; j++) {
                temp[i*BS + j] = a[size*(i + offset) + offset + j];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        for (int j = 0; j < BS; j++) {
            for (int i = 0; i < BS; i++) {
                float sum = 0.f;
                for (int k = 0; k < i; k++) {
                    sum += temp[BS*i + k] * BB(i_global + k, j_global + j);
                }
                BB(i_global + i, j_global + j) = BB(i_global + i, j_global + j) - sum;
            }
        }
    } else {
        // Column update
        j_global = offset;
        i_global += BS * (chunk_idx + 1);

        // Load diagonal block to temp
        for (int i = 0; i < BS; i++) {
            for (int j = 0; j < BS; j++) {
                temp[i*BS + j] = a[size*(i + offset) + offset + j];
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        for (int i = 0; i < BS; i++) {
            for (int j = 0; j < BS; j++) {
                float sum = 0.f;
                for (int k = 0; k < j; k++) {
                    sum += BB(i_global + i, j_global + k) * temp[BS*k + j];
                }
                int i_here = i_global + i;
                int j_here = j_global + j;
                a[size*i_here + j_here] = (a[size*i_here + j_here] - sum) / a[size*(offset + j) + offset + j];
            }
        }
    }
}

__kernel void lud_internal(__global float* a, __local float* temp_top, __local float* temp_left, const int size, const int offset)
{
    int chunk_idx_x = get_global_id(0);
    int chunk_idx_y = get_global_id(1);

    int size_inter = size - offset - BS;
    int chunks_in_inter_row = size_inter / BS;

    if (chunk_idx_x >= chunks_in_inter_row || chunk_idx_y >= chunks_in_inter_row) return;

    int i_global = offset + BS * (1 + chunk_idx_y);
    int j_global = offset + BS * (1 + chunk_idx_x);

    // Load top block to temp_top and left block to temp_left
    for (int i = 0; i < BS; i++) {
        for (int j = 0; j < BS; j++) {
            temp_top[i*BS + j] = a[size*(i + offset) + j + j_global];
            temp_left[i*BS + j] = a[size*(i + i_global) + offset + j];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    float sum[BS];
    for (int idx = 0; idx < BS; idx++) sum[idx] = 0.f;

    for (int i = 0; i < BS; i++) {
        for (int k = 0; k < BS; k++) {
            for (int j = 0; j < BS; j++) {
                sum[j] += temp_left[BS*i + k] * temp_top[BS*k + j];
            }
        }
        for (int j = 0; j < BS; j++) {
            int row = i + i_global;
            int col = j + j_global;
            a[size*row + col] -= sum[j];
            sum[j] = 0.f;
        }
    }
}
